from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to turn ordinal prefixes into words
    _ordinal_map = {
        "1st": "first",
        "2nd": "second",
        "3rd": "third",
        "4th": "fourth",
        "5th": "fifth",
        "6th": "sixth",
        "7th": "seventh",
        "8th": "eighth",
        "9th": "ninth",
        "10th": "tenth",
    }

    # Collect phrases per subject
    subject_phrases: dict[str, list[str]] = {}

    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)

        # Determine phrase (without repeating subject)
        if p == "cityServed":
            phrase = f"serves the city of {o}"
        elif p == "location":
            phrase = f"is located in {o}"
        elif p == "country":
            phrase = f"is in {o}"
        elif p == "isPartOf":
            phrase = f"is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            phrase = f"lies at an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            phrase = f"lies at an elevation of {o} feet above sea level"
        elif p == "operatingOrganisation":
            phrase = f"is operated by {o}"
        elif p == "runwaySurfaceType":
            phrase = f"has a runway surface of {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            ord_word = _ordinal_map.get(idx, idx.lower())
            phrase = f"has a {ord_word} runway {o} feet long"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            ord_word = _ordinal_map.get(idx, idx.lower())
            phrase = f"has a {ord_word} runway {o} metres long"
        elif p == "runwayName":
            phrase = f"has a runway named {o}"
        elif p == "runwayLength":
            phrase = f"has a runway length of {o} metres"
        else:
            phrase = f"has {p} {o}"

        subject_phrases.setdefault(s, []).append(phrase)

    # Build complex sentence
    clauses: list[str] = []
    for subj, phrases in subject_phrases.items():
        if len(phrases) == 1:
            clause = f"{subj} {phrases[0]}."
        else:
            # join with commas and an 'and' before the last phrase
            all_but_last = ", ".join(phrases[:-1])
            clause = f"{subj} {all_but_last}, and {phrases[-1]}."
        clauses.append(clause)

    # Combine clauses into one paragraph
    sentence = " ".join(clauses)
    # Ensure first character is capitalised (subjects already capitalised)
    return sentence

# EVOLVE-BLOCK-END

